#!/usr/bin/env python3
"""Generate real educational content for Earth Science JSON."""
import json, os

def L(title, html, cards, quiz):
    """Build lesson tuple."""
    return (title, html, cards, quiz)

def Q(text, opts, explanation):
    """Build quiz question. Mark correct answer with * prefix."""
    return (text, opts, explanation)

def build_json(course_name, units_data):
    data = {}
    for unit_num, lessons in sorted(units_data.items()):
        for idx, (title, summary_html, flashcards, quiz) in enumerate(lessons, 1):
            key = f"u{unit_num}_l{unit_num}.{idx}"
            fc_list = [{"question": t, "answer": d, "data_i18n_q": None, "data_i18n_a": None} for t, d in flashcards]
            q_list = []
            for qi, (qt, opts, exp) in enumerate(quiz, 1):
                options = []
                for o in opts:
                    correct = o.startswith("*")
                    options.append({"text": o.lstrip("*"), "is_correct": correct, "data_i18n": None})
                q_list.append({
                    "question_number": qi, "question_text": qt, "attempted": 2,
                    "data_i18n": None, "options": options, "explanation": exp
                })
            data[key] = {
                "unit": unit_num, "lesson_number": f"{unit_num}.{idx}", "title": title,
                "course": course_name,
                "summary_sections": [{"title": f"Key Concepts: {title}", "content_html": summary_html, "data_i18n": None}],
                "flashcards": fc_list, "quiz_questions": q_list
            }
    return data

